/// <summary>
/// Holds partitioned rate limiters built once from <see cref="RateLimitingOptions"/>.
/// </summary>
public sealed class RateLimiterRegistry : IDisposable
{
    public PartitionedRateLimiter<HttpContext> General { get; }
    public PartitionedRateLimiter<HttpContext> Auth { get; }
    public PartitionedRateLimiter<HttpContext> Refresh { get; }

    public RateLimiterRegistry(IOptions<RateLimitingOptions> options)
    {
        var value = options.Value;
        General = CreateLimiter("general", value.General);
        Auth = CreateLimiter("auth", value.Auth);
        Refresh = CreateLimiter("refresh", value.Refresh);
    }

    private static PartitionedRateLimiter<HttpContext> CreateLimiter(
        string prefix,
        RateLimitWindowOptions window)
    {
        var permitLimit = Math.Max(1, window.PermitLimit);
        var windowSeconds = Math.Max(1, window.WindowSeconds);

        return PartitionedRateLimiter.Create<HttpContext, string>(
            context => RateLimitPartition.GetFixedWindowLimiter(
                partitionKey: $"{prefix}:{context.Connection.RemoteIpAddress?.ToString() ?? "unknown"}",
                factory: _ => new FixedWindowRateLimiterOptions
                {
                    PermitLimit = permitLimit,
                    Window = TimeSpan.FromSeconds(windowSeconds),
                    AutoReplenishment = true,
                    QueueLimit = 0
